    // If multiple sources reach it at the minimum time, we choose the one with the maximum color.

    // Initialize the result grid: stores the minimum time to reach (r, c), initialized to infinity.
    const minTime = Array(n).fill(0).map(() => Array(m).fill(Infinity));

    // Initialize the final color grid: stores the resulting color, initialized to 0 (uncolored).
